  ('generalpolice-3218f787-moex-00169', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'essay', '現今社會工作的實施領域相當廣泛，包括兒童與少年服務、老人服務等
等，請列出 5項社會工作實施領域，說明各領域所關注的核心問題及警
察人員可以協助的部分。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00170', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '社會工作實務非常強調社會工作者必須號召網絡成員一同提供服務，這種網絡合作模式並非基於 下列何種服務考量？', '["藉由合作服務，可匯集各專業的服務優勢", "可減少原有服務的重疊與缺乏協調性", "合作過程中，各專業可學習彼此所長", "各專業可逃避服務義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00171', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於社會工作倫理重要性的陳述與說明，何者錯誤？', '["社會工作倫理是在提醒工作者單一價值的重要性，使其建立個人的信念，而能有一個單一判斷 的準則", "專業倫理是一種集體的良心，社會工作倫理則反映出社會工作者的集體良心", "社會工作倫理的相對論觀點認為，沒有放諸四海皆準的倫理守則，所以一般而言，信守承諾是 對的，但在特殊情況下，信守承諾是可以被打破的", "社會工作者需要培養超越性的價值觀與人生信念，才能在面對困難的案主具有優質的服務策 略，又不失人性化的倫理守則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00172', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於社會工作督導觀點的敘述，何者正確？', '["危機處理的督導觀點，是一種問題取向的觀點，督導者主要在協助被督導者該如何處理案主的 問題，以免產生危機", "發展性的督導觀點，認為督導的目的在於使受督導的社會工作者發展自身的專業認同，促進其 對專業角色的信心", "社會學習的督導觀點，認為督導的任務主要是協助受督導者學習如何將理論應用在處理案主所 面對的社會問題", "心理動力的督導觀點，主要在協助接受督導的社會工作者，與案主共同找出過去處理問題的成 功因素及復原力，以處理目前的問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00173', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於社會個案工作中「個案紀錄」的說明，何者錯誤？', '["個案工作者將和案主或重要關係人互動的重點加以記錄，便稱之為個案紀錄", "在個案紀錄中常使用家系圖及生態圖來說明案主、家庭及外在系統間的關聯性", "個案紀錄的類型包括過程紀錄、摘要紀錄與問題取向紀錄", "個案紀錄中應附家系圖，圖中通常以三角形（△）的符號代表男性，而以圓形（○）的符號代 表女性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00174', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列敘述何者並非社會工作者所應具備的價值體系？', '["每一個人生而具有其價值及尊嚴", "每一個人的生命價值在於其生而自由平等", "每一個人因為會與環境互動而形成其共同性", "每一個人可運用其所擁有的資源增強能力或激發潛能，以達成自我實現"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00175', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於社會個案工作所使用模式的說明，何者錯誤？', '["任務中心模式對社會工作重要的貢獻在於，其將關注的焦點從個人治療的取向轉移到問題解決 的取向", "危機介入模式乃是，案主透過社會個案工作者適當的支持與協助，學會處理危機的新方法及發 展有效的因應機制，使危機變成轉機", "衝突模式，此模式主要是協助個人處理與其生活環境間，在互動過程中所產生的衝突與矛盾", "生活模式，其目的在於提升個人與其環境的適應度，社會個案工作者的任務在於協助案主與其 環境進行協商"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
